pathFile <- function(filename=character(0), filedir=character(0)) {
   print("------pathFile------")

   if (length(filename) != 0) {
      filename <- basename(filename);
   }#if
   if (length(filename) == 0) {
      filename <- as.character("ERROR_MISSING_FILENAME");
   }#if
   if (dirname(filename) != ".") {
      filedir <- dirname(filename);
